class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.size();
        vector<int> max_len(n);
        for (int i = 0; i < n; ++i) {
            if (i > 0) max_len[i] = max_len[i-1];
            for (int j = i + 3; j < n; ++j) {
                if (word[i] == word[j]) {
                    max_len[j] = max(max_len[j], max_len[i-1] + 1);
                }
            }
        }
        return max_len.back();
    }
};
